+                if context.sourceMode == .auto, self.shouldFallbackToClaudeCLI(for: error) {
+                    self.writeStderr(
+                        "Warning: Claude web cookies unavailable (\(error.localizedDescription)). " +
+                            "Falling back to Claude CLI.\n")
